('chk-manual-testing-review', 'ph-manual-testing', 90, 'checkpoint', 'gate', NULL, NULL, 'Manual Testing Review Gate', 'Review checkpoint for Manual Testing and Test Design. The learner consolidates evidence from Writing Clear Test Cases, Equivalence Partitioning, Boundary Value Analysis, Decision Table Testing, identifies unresolved prerequisite gaps, and decides whether to continue, review selected topics, or complete extra practice before the next roadmap segment.', 'This checkpoint acts as a transition gate for the software quality assurance roadmap. It supports reflection and planning; it is not a certification, mastery test, or claim of job readiness.', 'checkpoint', 'ph-manual-testing', 2, 90, 1, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "checkpoint", "checkpointPurpose": "phase_review", "reviewMode": "gate", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Summarize the main concepts and decisions from Manual Testing and Test Design in practical software quality assurance terms.", "Identify prerequisite gaps, unclear topics, or risks that should be reviewed before moving forward.", "Create a short evidence artifact that links completed roadmap items to what was learned."]'::jsonb, '["List the roadmap items reviewed for this checkpoint.", "Provide one evidence artifact such as notes, a diagram, a lab result, code, queries, screenshots, or a project review.", "Record at least two gaps, risks, or follow-up actions, or explicitly state that no critical gaps were found.", "Use the result to choose one next step: continue, review selected topics, or complete extra practice."]'::jsonb),
('proj-manual-test-suite', 'ph-manual-testing', 100, 'project', NULL, NULL, NULL, 'Required Manual Test Suite', 'Milestone project brief: Build a manual regression suite for login, profile, search, filtering, form validation, and error handling. Build a reviewable frontend feature slice that demonstrates the main decisions from Manual Testing and Test Design. Expected evidence includes a focused UI flow or component set, state, validation, API, or accessibility behavior where relevant, and screenshots plus notes on edge cases. Keep scope focused so the result can be completed, checked, and explained.', 'This required milestone project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-manual-testing', 2, 100, 5, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "milestone_practice","projectKind": "frontend_app","projectScope": "focused_milestone","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define the user flow and states","implement the UI slice","verify accessibility and edge cases","document screenshots and trade-offs"],"expectedEvidence": ["a focused UI flow or component set","state, validation, API, or accessibility behavior where relevant","screenshots plus notes on edge cases"],"optionalPractice": false,"milestone": true}'::jsonb, true, true, '["Build a focused Manual Test Suite artifact that demonstrates the main concepts from Manual Testing and Test Design.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a focused UI flow or component set, state, validation, API, or accessibility behavior where relevant, and screenshots plus notes on edge cases.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb),
