('chk-web-tech-review', 'ph-web-tech', 90, 'checkpoint', 'assessment', NULL, NULL, 'Web and API Foundations Gate', 'Practical checkpoint for Web, API, and Developer Foundations. The learner completes a small diagnostic task or review artifact using Internet Basics, HTTP Fundamentals, HTML, CSS, and JavaScript Basics, Browser DevTools for QA and records observations that can guide further practice.', 'This checkpoint gives the software quality assurance roadmap a reviewable activity at the end of a technical segment instead of a passive completion checkbox. It does not independently verify mastery.', 'checkpoint', 'ph-web-tech', 3, 90, 2, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "checkpoint", "checkpointPurpose": "phase_review", "reviewMode": "assessment", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Apply selected concepts from Web, API, and Developer Foundations to a small practical scenario.", "Explain what worked, what failed, and which signals were used to debug or validate the result.", "Translate the result into a short next-action plan for continued learning."]'::jsonb, '["Complete a small practical task, lab, review exercise, or worked example related to this segment.", "Attach or describe the output, result, or evidence used for review.", "Explain at least one mistake, trade-off, or failure mode encountered during the task.", "Write the next practice action based on the result."]'::jsonb),
('proj-api-web-test-notes', 'ph-web-tech', 100, 'project', NULL, NULL, NULL, 'Required Web/API Investigation Report', 'Milestone project brief: Investigate a demo web app using DevTools, API calls, and SQL-style data checks, then document findings and risks. Build a reviewable database implementation lab that demonstrates the main decisions from Web, API, and Developer Foundations. Expected evidence includes schema, query, or migration artifacts, before/after evidence such as query plans or checks, and notes on consistency, performance, or recovery trade-offs. Keep scope focused so the result can be completed, checked, and explained.', 'This required milestone project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-web-tech', 3, 100, 5, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "milestone_practice","projectKind": "database_lab","projectScope": "focused_milestone","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define the data model or query scenario","implement schema/query/migration changes","compare behavior before and after","document trade-offs"],"expectedEvidence": ["schema, query, or migration artifacts","before/after evidence such as query plans or checks","notes on consistency, performance, or recovery trade-offs"],"optionalPractice": false,"milestone": true}'::jsonb, true, true, '["Build a focused Web/API Investigation Report artifact that demonstrates the main concepts from Web, API, and Developer Foundations.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes schema, query, or migration artifacts, before/after evidence such as query plans or checks, and notes on consistency, performance, or recovery trade-offs.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb),
('proj-devtools-network-lab', 'ph-web-tech', 111, 'project', NULL, NULL, NULL, 'DevTools Network Lab', 'Optional project brief: Analyze request waterfall, cookies, response codes, caching, and failed requests in a browser session. Build a small, reviewable frontend feature slice to practice ideas from Web, API, and Developer Foundations. Expected evidence includes a focused UI flow or component set, state, validation, API, or accessibility behavior where relevant, and screenshots plus notes on edge cases. Keep it lightweight; the goal is applied practice and clearer portfolio evidence, not a mandatory milestone.', 'This optional practice project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-web-tech', 3, 111, 2, 'beginner', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "optional_practice","projectKind": "frontend_app","projectScope": "small_practice_artifact","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define the user flow and states","implement the UI slice","verify accessibility and edge cases","document screenshots and trade-offs"],"expectedEvidence": ["a focused UI flow or component set","state, validation, API, or accessibility behavior where relevant","screenshots plus notes on edge cases"],"optionalPractice": true,"milestone": false}'::jsonb, false, true, '["Build a small DevTools Network Lab artifact to practice selected concepts from Web, API, and Developer Foundations.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a focused UI flow or component set, state, validation, API, or accessibility behavior where relevant, and screenshots plus notes on edge cases.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb),
