('chk-mobile-review', 'ph-mobile-desktop-testing', 90, 'checkpoint', 'gate', NULL, NULL, 'Mobile and Cross-Platform Review Gate', 'Review checkpoint for Mobile, Desktop, and Cross-Platform Testing. The learner consolidates evidence from Mobile Testing Fundamentals, Android and iOS Basics for QA, Emulators, Simulators, and Real Devices, Mobile Network and Offline Testing, identifies unresolved prerequisite gaps, and decides whether to continue, review selected topics, or complete extra practice before the next roadmap segment.', 'This checkpoint acts as a transition gate for the software quality assurance roadmap. It supports reflection and planning; it is not a certification, mastery test, or claim of job readiness.', 'checkpoint', 'ph-mobile-desktop-testing', 8, 90, 1, 'intermediate', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "checkpoint", "checkpointPurpose": "phase_review", "reviewMode": "gate", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Summarize the main concepts and decisions from Mobile, Desktop, and Cross-Platform Testing in practical software quality assurance terms.", "Identify prerequisite gaps, unclear topics, or risks that should be reviewed before moving forward.", "Create a short evidence artifact that links completed roadmap items to what was learned."]'::jsonb, '["List the roadmap items reviewed for this checkpoint.", "Provide one evidence artifact such as notes, a diagram, a lab result, code, queries, screenshots, or a project review.", "Record at least two gaps, risks, or follow-up actions, or explicitly state that no critical gaps were found.", "Use the result to choose one next step: continue, review selected topics, or complete extra practice."]'::jsonb),
('proj-mobile-test-matrix', 'ph-mobile-desktop-testing', 100, 'project', NULL, NULL, NULL, 'Required Mobile Test Matrix', 'Milestone project brief: Create a mobile compatibility and risk matrix with device coverage, OS coverage, network scenarios, and release checklist. Build a reviewable security review artifact that demonstrates the main decisions from Mobile, Desktop, and Cross-Platform Testing. Expected evidence includes a scoped security review artifact, risks mapped to controls or mitigations, and clear boundaries and residual-risk notes. Keep scope focused so the result can be completed, checked, and explained.', 'This required milestone project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-mobile-desktop-testing', 8, 100, 5, 'intermediate', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "milestone_practice","projectKind": "security_review","projectScope": "focused_milestone","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define a safe scope and scenario","identify risks or controls","map findings to mitigation actions","state boundaries and residual risks"],"expectedEvidence": ["a scoped security review artifact","risks mapped to controls or mitigations","clear boundaries and residual-risk notes"],"optionalPractice": false,"milestone": true}'::jsonb, true, true, '["Build a focused Mobile Test Matrix artifact that demonstrates the main concepts from Mobile, Desktop, and Cross-Platform Testing.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a scoped security review artifact, risks mapped to controls or mitigations, and clear boundaries and residual-risk notes.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb),
('proj-appium-smoke-suite', 'ph-mobile-desktop-testing', 111, 'project', NULL, NULL, NULL, 'Appium Smoke Suite', 'Optional project brief: Automate a small mobile smoke flow using Appium or a comparable mobile automation tool. Build a small, reviewable mobile app slice to practice ideas from Mobile, Desktop, and Cross-Platform Testing. Expected evidence includes a focused mobile user flow, local state, navigation, or API integration as appropriate, and screenshots or emulator notes explaining behavior. Keep it lightweight; the goal is applied practice and clearer portfolio evidence, not a mandatory milestone.', 'This optional practice project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-mobile-desktop-testing', 8, 111, 3, 'intermediate', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "optional_practice","projectKind": "mobile_app","projectScope": "small_practice_artifact","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["define the main user journey","build the smallest complete flow","test on emulator or device","capture screenshots and known limitations"],"expectedEvidence": ["a focused mobile user flow","local state, navigation, or API integration as appropriate","screenshots or emulator notes explaining behavior"],"optionalPractice": true,"milestone": false}'::jsonb, false, true, '["Build a small Appium Smoke Suite artifact to practice selected concepts from Mobile, Desktop, and Cross-Platform Testing.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a focused mobile user flow, local state, navigation, or API integration as appropriate, and screenshots or emulator notes explaining behavior.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb),
