('api-testing-interview', 'grp-interview-readiness', 3, 'topic', NULL, NULL, NULL, 'API Testing Interview Readiness', 'Explain API coverage, auth testing, schema validation, negative tests, and data validation.', 'This item builds practical QA capability for api testing interview readiness.', 'side', 'grp-interview-readiness', 14, 203, 1, 'intermediate', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "side"}'::jsonb, true, true, '["Explain how API Testing Interview Readiness affects practical quality assurance engineering work.", "Apply API Testing Interview Readiness to design test coverage or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of API Testing Interview Readiness.", "Document evidence, risks, and next steps."]'::jsonb),
('behavioral-quality-stories', 'grp-interview-readiness', 4, 'topic', NULL, NULL, NULL, 'Behavioral Quality Stories', 'Prepare STAR stories about bugs found, risk prevented, collaboration, ambiguity, and release decisions.', 'This item builds practical QA capability for behavioral quality stories.', 'side', 'grp-interview-readiness', 14, 204, 1, 'intermediate', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "side"}'::jsonb, true, true, '["Explain how Behavioral Quality Stories affects practical quality assurance engineering work.", "Apply Behavioral Quality Stories to design test coverage or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Demonstrate practical understanding of Behavioral Quality Stories.", "Document evidence, risks, and next steps."]'::jsonb),
('chk-final-qa-review', 'ph-portfolio-capstone', 90, 'checkpoint', 'gate', NULL, NULL, 'Final QA Roadmap Review Gate', 'Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the software quality assurance path.', 'This checkpoint closes the suggested software quality assurance orientation path by organizing evidence and next steps. It is not an employment guarantee or formal competency certification.', 'checkpoint', 'ph-portfolio-capstone', 14, 90, 2, 'advanced', 100, NULL, NULL, '{"source": "roadmap.sh/qa", "visualRole": "checkpoint", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent software quality assurance learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('proj-qa-capstone', 'ph-portfolio-capstone', 100, 'project', NULL, NULL, NULL, 'Required QA Engineer Capstone Project', 'Capstone project brief: Test a realistic web application end-to-end with test strategy, manual suite, API automation, UI automation, accessibility/security checks, performance smoke test, CI reporting, and final quality report. Build it as an integrated quality engineering artifact for the QA Engineer roadmap, with enough scope to connect multiple earlier topics from Portfolio, Interview Readiness, and Capstone. Expected evidence includes a test plan or automation suite, sample defects or risk notes, and execution evidence with pass/fail output. Keep the implementation reviewable: define the problem, show the working path, validate the result, and document limitations rather than claiming production readiness.', 'This capstone project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-portfolio-capstone', 14, 100, 8, 'advanced', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "capstone","projectKind": "qa_project","projectScope": "integrated_multi_topic","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["identify risks and test targets","design manual and/or automated checks","run the checks and capture output","summarize defects and coverage gaps"],"expectedEvidence": ["a test plan or automation suite","sample defects or risk notes","execution evidence with pass/fail output"],"optionalPractice": false,"milestone": true,"capstone": true}'::jsonb, true, true, '["Plan and build an integrated QA Engineer Capstone Project that connects multiple topics from the QA Engineer roadmap.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a test plan or automation suite, sample defects or risk notes, and execution evidence with pass/fail output.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement.","The project connects at least three earlier roadmap topics and explains how they interact."]'::jsonb),
('proj-mock-release-go-no-go', 'ph-portfolio-capstone', 111, 'project', NULL, NULL, NULL, 'Mock Release Go/No-Go Report', 'Optional project brief: Prepare a release readiness report with quality signals, defects, risks, and recommendation. Build a small, reviewable model or AI feature project to practice ideas from Portfolio, Interview Readiness, and Capstone. Expected evidence includes a reproducible notebook or small service, evaluation examples with metrics or qualitative checks, and documented model, prompt, or retrieval limitations. Keep it lightweight; the goal is applied practice and clearer portfolio evidence, not a mandatory milestone.', 'This optional practice project turns the surrounding QA Engineer topics into a concrete artifact. It gives the learner a clearer target, suggested build path, and review evidence without treating completion as proof of mastery or job readiness.', 'side', 'ph-portfolio-capstone', 14, 111, 2, 'advanced', 100, NULL, NULL, '{"source": "roadmap.sh/qa","visualRole": "side","projectPurpose": "optional_practice","projectKind": "ml_ai","projectScope": "small_practice_artifact","evidenceRequired": true,"claimLimit": "reviewable_project_evidence_only_not_mastery_or_job_readiness","suggestedSteps": ["select a small dataset or task","build the baseline or feature slice","evaluate outputs against clear examples","document failure modes and next improvements"],"expectedEvidence": ["a reproducible notebook or small service","evaluation examples with metrics or qualitative checks","documented model, prompt, or retrieval limitations"],"optionalPractice": true,"milestone": false}'::jsonb, false, true, '["Build a small Mock Release Go/No-Go Report artifact to practice selected concepts from Portfolio, Interview Readiness, and Capstone.","Explain the main design, data, tooling, or workflow decisions used in the project.","Validate the project with appropriate evidence such as tests, screenshots, logs, metrics, queries, or review notes.","Document setup, usage, limitations, and at least one follow-up improvement."]'::jsonb, '["A repository, notebook, dashboard, write-up, prototype, or configuration artifact is available for review.","The README or project notes state the project goal, setup steps, usage path, and expected output.","The deliverable includes a reproducible notebook or small service, evaluation examples with metrics or qualitative checks, and documented model, prompt, or retrieval limitations.","The learner records validation evidence such as tests, screenshots, logs, metrics, query results, playtest notes, or manual verification steps.","The review notes identify trade-offs, limitations, and one reasonable next improvement."]'::jsonb)
;

SELECT sn.node_id, m.roadmap_version_id, parent.node_id, sn.node_key, sn.node_type, sn.checkpoint_type, sn.selection_type, sn.required_count, sn.title, sn.description, sn.reason, sn.order_index, sn.layout_role, sn.layout_group, sn.layout_rank, sn.layout_order, sn.estimated_hours, sn.difficulty_level, sn.priority, sn.position_x, sn.position_y, sn.metadata, sn.is_required, sn.is_trackable, sn.learning_outcomes, sn.completion_criteria FROM seed_node sn CROSS JOIN seed_roadmap_map m LEFT JOIN seed_node parent ON parent.node_key = sn.parent_key
ON CONFLICT (roadmap_version_id, slug) DO UPDATE SET parent_node_id = EXCLUDED.parent_node_id, node_type = EXCLUDED.node_type, checkpoint_type = EXCLUDED.checkpoint_type, selection_type = EXCLUDED.selection_type, required_count = EXCLUDED.required_count, title = EXCLUDED.title, description = EXCLUDED.description, reason = EXCLUDED.reason, order_index = EXCLUDED.order_index, layout_role = EXCLUDED.layout_role, layout_group = EXCLUDED.layout_group, layout_rank = EXCLUDED.layout_rank, layout_order = EXCLUDED.layout_order, estimated_hours = EXCLUDED.estimated_hours, difficulty_level = EXCLUDED.difficulty_level, priority = EXCLUDED.priority, position_x = EXCLUDED.position_x, position_y = EXCLUDED.position_y, metadata = EXCLUDED.metadata, is_required = EXCLUDED.is_required, is_trackable = EXCLUDED.is_trackable, learning_outcomes = EXCLUDED.learning_outcomes, completion_criteria = EXCLUDED.completion_criteria;

-- Node-skill mappings.
DROP TABLE IF EXISTS seed_node_skill;
CREATE TEMP TABLE seed_node_skill (node_key text NOT NULL, skill_slug text NOT NULL) ON COMMIT DROP;


