SELECT DISTINCT
    rn.roadmap_node_id,
    resolved_skill.skill_id
FROM seed_node_skill sns
JOIN seed_roadmap_map m
    ON true
JOIN public.roadmap_node rn
    ON rn.roadmap_version_id = m.roadmap_version_id
   AND rn.slug = sns.node_key
LEFT JOIN seed_skill ss
    ON ss.slug = sns.skill_slug
JOIN LATERAL (
    SELECT s.skill_id
    FROM public.skill s
    WHERE s.slug = sns.skill_slug
       OR (ss.name IS NOT NULL AND s.name = ss.name)
    ORDER BY
        CASE WHEN s.slug = sns.skill_slug THEN 0 ELSE 1 END
    LIMIT 1
) resolved_skill ON true
ON CONFLICT (roadmap_node_id, skill_id) DO NOTHING;

-- Node-resource mappings.
DROP TABLE IF EXISTS seed_node_resource;
-- Choice group resources are intentionally pushed down to actionable child nodes; computed group nodes should not carry learning resources.
CREATE TEMP TABLE seed_node_resource (node_key text NOT NULL, resource_key text NOT NULL, order_index int NOT NULL) ON COMMIT DROP;

WITH deduped_node_resource AS (
    SELECT DISTINCT ON (rn.roadmap_node_id, lr.learning_resource_id)
        rn.roadmap_node_id,
        lr.learning_resource_id AS learning_resource_id,
        snr.order_index,
        (snr.order_index <= 3) AS is_primary
    FROM seed_node_resource snr
JOIN seed_node sn ON sn.node_key = snr.node_key
JOIN seed_roadmap_map m ON true
JOIN public.roadmap_node rn ON rn.roadmap_version_id = m.roadmap_version_id AND rn.slug = sn.node_key
JOIN seed_resource sr ON sr.resource_key = snr.resource_key
JOIN public.learning_resource lr ON lr.url = sr.url
    ORDER BY rn.roadmap_node_id, lr.learning_resource_id, snr.order_index
)
SELECT roadmap_node_id, learning_resource_id, order_index, is_primary
FROM deduped_node_resource
ON CONFLICT (roadmap_node_id, learning_resource_id) DO UPDATE SET
    order_index = EXCLUDED.order_index,
    is_primary = EXCLUDED.is_primary;

SELECT DISTINCT lr.learning_resource_id, s.skill_id FROM seed_node_resource snr JOIN seed_node_skill sns ON sns.node_key = snr.node_key JOIN seed_resource sr ON sr.resource_key = snr.resource_key JOIN public.learning_resource lr ON lr.url = sr.url JOIN seed_skill ss ON ss.slug = sns.skill_slug JOIN public.skill s ON s.slug = ss.slug OR s.name = ss.name ON CONFLICT (learning_resource_id, skill_id) DO NOTHING;

-- Roadmap edges.
DROP TABLE IF EXISTS seed_edge;
CREATE TEMP TABLE seed_edge (from_key text NOT NULL, to_key text NOT NULL, edge_type text NOT NULL, dependency_type text NOT NULL, condition jsonb NOT NULL) ON COMMIT DROP;

SELECT m.roadmap_version_id, source.roadmap_node_id, target.roadmap_node_id, se.edge_type, se.dependency_type, se.condition FROM seed_edge se CROSS JOIN seed_roadmap_map m JOIN public.roadmap_node source ON source.roadmap_version_id = m.roadmap_version_id AND source.slug = se.from_key JOIN public.roadmap_node target ON target.roadmap_version_id = m.roadmap_version_id AND target.slug = se.to_key ON CONFLICT (roadmap_version_id, from_node_id, to_node_id, edge_type) DO UPDATE SET dependency_type = EXCLUDED.dependency_type, condition = EXCLUDED.condition;

COMMIT;

-- Summary: Skills 271, Learning resources 121, Roadmap nodes 257, Node-skill mappings 635, Node-resource mappings 1336, Edges 304, Required trackable hours 405, All trackable hours 434, Roadmap estimated_total_hours 420.